#!/usr/bin/env Rscript
# 06_figures.R
# ------------
# Generates Figures 5, 6, and 7 from the paper.
# (Figures 3 and 4 are generated by scripts/03_figures_34.R)
#
# Inputs (from output/tables/<network_version>/):
#   summary_network_property_matchRP_combine_sample.csv  (Figure 5)
#   ate_sample500_tau1_0_0.1_tau2_0_sim100.csv          (Figure 6)
#   a_degree.csv                                         (Figure 6)
#
# Outputs (saved to output/figures/):
#   Figure5_representativeness.pdf
#   Figure6_ate.pdf
#   Figure7_cate.pdf
#
# Usage:
#   Rscript scripts/06_figures.R
#   Or open in RStudio and run interactively.
#
# Required packages: tidyverse, patchwork, grid, cowplot, ggbreak
# Install: install.packages(c("tidyverse","patchwork","cowplot","ggbreak"))

# Set working directory to output/tables where network subdirs live
output_tables <- file.path(dirname(rstudioapi::getSourceEditorContext()$path),
                           "..", "output", "tables")
if (!interactive()) {
  output_tables <- file.path("output", "tables")
}
output_figures <- file.path(dirname(output_tables), "figures")
dir.create(output_figures, showWarnings = FALSE, recursive = TRUE)

library(tidyverse)
library(patchwork)
library(grid)

# ---------------------------------------------------------
# Theme
# ---------------------------------------------------------
theme_mksc <- function() {
  theme_minimal(base_size = 10) +
    theme(
      panel.grid.major.x = element_blank(),
      panel.grid.minor = element_blank(),
      panel.grid.major.y = element_line(color = "grey82", linewidth = 0.3),
      axis.title.x = element_blank(),
      axis.title.y = element_text(size = 10),
      axis.text.x  = element_text(angle = 30, hjust = 1, size = 9),
      axis.text.y  = element_text(size = 9),
      plot.title   = element_text(size = 10.5, hjust = 0.3, face = "plain"),
      legend.position = "bottom",
      legend.box = "horizontal",
      legend.key.width  = unit(2.2, "lines"),
      legend.key.height = unit(1.0, "lines"),
      legend.text  = element_text(size = 10),
      legend.title = element_text(size = 10),
      legend.justification = "left",
      legend.box.just = "left",
      plot.margin = margin(5, 5, 5, 5)
    )
}

# ---------------------------------------------------------
# File names and network names
# ---------------------------------------------------------
file_name <- "summary_network_property_matchRP_combine_sample.csv"

versions_ab <- c(
  "lastfm",
  "twitch",
  "pokec",
  "simulate_small",
  "simulate_base",
  "simulate_sparse"
)

group_names_ab <- c(
  "lastfm"                            = "LastFM",
  "twitch"                         = "Twitch",
  "pokec"                             = "Pokec",
  "simulate_small" = "Small",
  "simulate_base"  = "Base",
  "simulate_sparse" = "Sparse"
)

versions_c <- c(
  "simulate_small",
  "simulate_base",
  "simulate_sparse"
)

group_names_c <- c(
  "simulate_small" = "Small",
  "simulate_base"  = "Base",
  "simulate_sparse" = "Sparse"
)

# ---------------------------------------------------------
# Build data for Panels A and B
# ---------------------------------------------------------
combined_data_ab <- map_dfr(versions_ab, function(v) {
  file_path <- file.path(v, file_name)
  df <- read.csv(file_path)
  df$group <- group_names_ab[[v]]
  
  long_abs <- df %>%
    pivot_longer(
      cols = c("represent", "remove"),
      names_to = "version",
      values_to = "value"
    )
  
  long_ratio <- df %>%
    pivot_longer(
      cols = c("rp_vs_population", "rm_vs_population"),
      names_to = "version",
      values_to = "KS"
    ) %>%
    mutate(
      version = recode(
        version,
        "rp_vs_population" = "represent",
        "rm_vs_population" = "remove"
      )
    )
  
  left_join(
    long_abs,
    long_ratio,
    by = c("variable", "population_value", "group", "version")
  ) %>%
    select(variable, population_value, group, version, value, KS)
})

combined_data_ab <- combined_data_ab %>%
  mutate(
    version = recode(
      version,
      "represent" = "Representative",
      "remove"    = "Excluding"
    ),
    variable = factor(
      variable,
      levels = c("degree", "clustering", "eigen_c", "nb_degree"),
      labels = c(
        "Degree",
        "Clustering Coefficient",
        "Eigenvector Centrality",
        "Neighbor Degree"
      )
    ),
    group = factor(
      group,
      levels = c("LastFM", "Twitch", "Pokec", "Small", "Base", "Sparse")
    ),
    NetworkType = case_when(
      group %in% c("LastFM", "Twitch", "Pokec") ~ "Real-world",
      group %in% c("Small", "Base", "Sparse") ~ "Simulated"
    )
  )

# ---------------------------------------------------------
# Build data for Panel C
# ---------------------------------------------------------
combined_data_c <- map_dfr(versions_c, function(v) {
  file_path <- file.path(v, file_name)
  df <- read.csv(file_path)
  df <- df[df$variable %in% c("cov_z1", "cov_z2", "cov_z3"), ]
  df$group <- group_names_c[[v]]
  
  long_abs <- df %>%
    pivot_longer(
      cols = c("represent", "remove"),
      names_to = "version",
      values_to = "value"
    )
  
  long_ratio <- df %>%
    pivot_longer(
      cols = c("rp_vs_population", "rm_vs_population"),
      names_to = "version",
      values_to = "KS"
    ) %>%
    mutate(
      version = recode(
        version,
        "rp_vs_population" = "represent",
        "rm_vs_population" = "remove"
      )
    )
  
  left_join(
    long_abs,
    long_ratio,
    by = c("variable", "population_value", "group", "version")
  ) %>%
    select(variable, population_value, group, version, value, KS)
})

combined_data_c <- combined_data_c %>%
  mutate(
    version = recode(
      version,
      "represent" = "Representative",
      "remove"    = "Excluding"
    ),
    variable = factor(
      variable,
      levels = c("cov_z1", "cov_z2", "cov_z3"),
      labels = c("Z1", "Z2", "Z3")
    ),
    group = factor(
      group,
      levels = c("Small", "Base", "Sparse")
    ),
    NetworkType = "Simulated"
  )

# ---------------------------------------------------------
# Styles
# ---------------------------------------------------------
color_map <- c(
  "Real-world" = "#2F2F2F",
  "Simulated"  = "#7A8FA6"
)

linetype_map <- c(
  "Excluding"      = "22",
  "Representative" = "solid"
)

shape_map <- c(
  "Excluding"      = 17,
  "Representative" = 16
)

# ---------------------------------------------------------
# Plot functions
# ---------------------------------------------------------
plot_variable_ab <- function(df, var_name, title_text, show_legend = FALSE) {
  df_sub <- df %>% filter(variable == var_name)
  
  p <- ggplot(
    df_sub,
    aes(
      x = group,
      y = KS,
      color = NetworkType,
      linetype = version,
      shape = version,
      group = interaction(NetworkType, version)
    )
  ) +
    geom_line(linewidth = 0.7) +
    geom_point(size = 2.2) +
    scale_color_manual(
      values = color_map,
      drop = FALSE,
      name = "Network Type"
    ) +
    scale_linetype_manual(
      values = linetype_map,
      name = "Method"
    ) +
    scale_shape_manual(
      values = shape_map,
      guide = "none"
    ) +
    expand_limits(y = 0) +
    scale_y_continuous(limits = c(0, 0.25))+
    labs(
      title = title_text,
      y = "KS Distance"
    ) +
    guides(
      color = guide_legend(
        order = 1,
        override.aes = list(
          linetype = "solid",
          shape = NA,
          linewidth = 1.2
        )
      ),
      linetype = guide_legend(
        order = 2,
        override.aes = list(
          color = "black",
          linewidth = 1.2,
          linetype = c("22", "solid"),
          lineend = "butt"
        )
      )
    ) +
    theme_mksc()
  
  if (!show_legend) {
    p <- p + theme(legend.position = "none")
  }
  
  p
}

plot_variable_c <- function(df, var_name, title_text, show_legend = FALSE) {
  df_sub <- df %>% filter(variable == var_name)
  
  p <- ggplot(
    df_sub,
    aes(
      x = group,
      y = KS,
      linetype = version,
      shape = version,
      group = version
    )
  ) +
    geom_line(
      linewidth = 0.7,
      color = color_map["Simulated"]
    ) +
    geom_point(
      size = 2.2,
      color = color_map["Simulated"]
    ) +
    scale_linetype_manual(
      values = linetype_map,
      name = "Method"
    ) +
    scale_shape_manual(
      values = shape_map,
      guide = "none"
    ) +
    expand_limits(y = 0) +
    scale_y_continuous(limits = c(0, 0.06))+
    labs(
      title = title_text,
      y = "KS Distance"
    )  +
    guides(
      linetype = guide_legend(
        order = 2,
        override.aes = list(
          color = "black",
          linewidth = 1.2
        )
      )
    ) +
    theme_mksc()
  
  if (!show_legend) {
    p <- p + theme(legend.position = "none")
  }
  
  p
}

# ---------------------------------------------------------
# Create plots
# Only one plot keeps the legend
# ---------------------------------------------------------
p_degree   <- plot_variable_ab(combined_data_ab, "Degree", "Degree", show_legend = TRUE)
p_cluster  <- plot_variable_ab(combined_data_ab, "Clustering Coefficient", "Clustering Coefficient")
p_eigen    <- plot_variable_ab(combined_data_ab, "Eigenvector Centrality", "Eigenvector Centrality")
p_neighbor <- plot_variable_ab(combined_data_ab, "Neighbor Degree", "Neighbor Degree")

p_z1 <- plot_variable_c(combined_data_c, "Z1", "Z1")
p_z2 <- plot_variable_c(combined_data_c, "Z2", "Z2")
p_z3 <- plot_variable_c(combined_data_c, "Z3", "Z3")

# ---------------------------------------------------------
# Panel headers
# ---------------------------------------------------------
header_a <- ggplot() +
  annotate("text", x = 0.5, y = 0.1, label = "Panel A. Optimization Variables",
           size = 4) +
  theme_void()

header_b <- ggplot() +
  annotate("text", x = 0.5, y = 0.1, label = "Panel B. Network Variables",
            size = 4) +
  theme_void()

header_c <- ggplot() +
  annotate("text", x = 0.5, y = 0.1, label = "Panel C. Other Individual Variables",
          size = 4) +
  theme_void()

# ---------------------------------------------------------
# Assemble panels
# ---------------------------------------------------------
panel_a <- wrap_plots(
  A = header_a,
  B = p_degree,
  C = p_cluster,
  design = "
  AAAAAA
  BBBCCC
  ",
  heights = c(0.3, 1)
)

panel_b <- wrap_plots(
  A = header_b,
  B = p_eigen,
  C = p_neighbor,
  design = "
  AAAAAA
  BBBCCC
  ",
  heights = c(0.3, 1)
)

panel_c <- wrap_plots(
  A = header_c,
  B = p_z1,
  C = p_z2,
  D = p_z3,
  design = "
  AAAAAAAAA
  BBBCCCDDD
  ",
  heights = c(0.3, 1)
)

# ---------------------------------------------------------
# Final figure
# ---------------------------------------------------------
figure5 <- wrap_plots(
  panel_a,
  panel_b,
  panel_c,
  ncol = 1
) +
  plot_layout(guides = "collect", heights = c(1, 1, 1)) &
  theme(
    legend.position = "bottom",
    legend.box = "horizontal",
    legend.justification = "left",
    legend.box.just = "left"
  )

figure5

# ---------------------------------------------------------
# Save
# ---------------------------------------------------------
ggsave(
  file.path(output_figures, "Figure5_representativeness.pdf"),
  figure5,
  width = 7.5,
  height = 6.75,
  units = "in"
)


