library(ggplot2)
library(cowplot)
library(dplyr)
library(patchwork)
library(ggbreak)
library(grid)

# ---------------------------------------------------------
# Working directory
# ---------------------------------------------------------
setwd("../output/tables")  # adjust if needed

# ---------------------------------------------------------
# Load data
# ---------------------------------------------------------
ate_table <- read.csv(file.path("simulate_base", "ate_sample500_tau1_0_0.1_tau2_0_sim100.csv"))
a_degree  <- read.csv(file.path("simulate_base", "a_degree.csv"), header = FALSE)

mean_degree <- mean(a_degree$V1)

# ---------------------------------------------------------
# Long estimator labels
# ---------------------------------------------------------
estimator_levels <- c(
  "Representative: Diff-in-Means",
  "Excluding: Diff-in-Means",
  "Excluding: Horvitz-Thompson",
  "Excluding: Hájek"
)

# ---------------------------------------------------------
# Prepare ADTE data
# ---------------------------------------------------------
adte_table <- ate_table %>%
  filter(estimator != "ols", tau2 == 0, estimand == "d10") %>%
  mutate(
    estimator = case_when(
      estimator == "diff-in-mean"     ~ "Excluding: Diff-in-Means",
      estimator == "Horvitz-Thompson" ~ "Excluding: Horvitz-Thompson",
      estimator == "Hajek"            ~ "Excluding: Hájek",
      estimator == "representative"   ~ "Representative: Diff-in-Means"
    ),
    power_percentage = power * 100,
    coverage_percentage = coverage * 100,
    Average_Treatment_Effect = tau1 * mean_degree
  )

adte_table$estimator <- factor(adte_table$estimator, levels = estimator_levels)

# ---------------------------------------------------------
# Prepare AITE data
# ---------------------------------------------------------
aite_table <- ate_table %>%
  filter(estimator != "ols", tau2 == 0, estimand == "d01") %>%
  mutate(
    estimator = case_when(
      estimator == "diff-in-mean"     ~ "Excluding: Diff-in-Means",
      estimator == "Horvitz-Thompson" ~ "Excluding: Horvitz-Thompson",
      estimator == "Hajek"            ~ "Excluding: Hájek",
      estimator == "representative"   ~ "Representative: Diff-in-Means"
    ),
    power_percentage = power * 100,
    coverage_percentage = coverage * 100,
    Average_Treatment_Effect = tau1 * mean_degree * 0.5
  )

aite_table$estimator <- factor(aite_table$estimator, levels = estimator_levels)

# ---------------------------------------------------------
# Aesthetics: color online, distinguishable in grayscale
# ---------------------------------------------------------
color_mapping <- c(
  "Representative: Diff-in-Means" = "#1F4E79",   # deep navy
  "Excluding: Diff-in-Means" = "#8B1E3F",        # dark red
  "Excluding: Horvitz-Thompson" = "#2F6B3B",    # dark green
  "Excluding: Hájek" = "#7A6F64"                # muted brown-gray
)

linetype_mapping <- c(
  "Representative: Diff-in-Means" = "solid",
  "Excluding: Diff-in-Means" = "44",
  "Excluding: Horvitz-Thompson" = "dotted",
  "Excluding: Hájek" = "dotdash"
)

shape_mapping <- c(
  "Representative: Diff-in-Means" = 16,
  "Excluding: Diff-in-Means" = 17,
  "Excluding: Horvitz-Thompson" = 15,
  "Excluding: Hájek" = 18
)

# ---------------------------------------------------------
# Theme
# ---------------------------------------------------------
theme_fig6 <- function() {
  theme_minimal(base_size = 10) +
    theme(
      panel.grid.major.x = element_blank(),
      panel.grid.minor = element_blank(),
      panel.grid.major.y = element_line(color = "grey92", linewidth = 0.25),
      panel.background = element_rect(fill = "white", color = NA),
      plot.background = element_rect(fill = "white", color = NA),
      plot.title = element_text(size = 11, hjust = 0.5, face = "plain"),
      axis.title = element_text(size = 10),
      axis.text = element_text(size = 9),
      legend.position = "bottom",
      legend.box = "horizontal",
      legend.key.width  = unit(3, "lines"),
      legend.key.height = unit(1.0, "lines"),
      legend.spacing.x  = unit(2, "cm"),
      legend.text = element_text(size = 8.5, margin = margin(r = 12)),
      legend.title = element_text(size = 9),
      plot.margin = margin(4, 4, 4, 4)
    )
}

# ---------------------------------------------------------
# Generic plotting function
# keep x-axis title only when requested
# ---------------------------------------------------------
plot_metric <- function(df, yvar, ylab, subtitle_text,
                        x_title = NULL,
                        show_legend = FALSE,
                        y_break = FALSE,
                        break_range = c(0.2, 1.0),
                        break_scale = 0.5) {
  
  present_levels <- estimator_levels[estimator_levels %in% unique(as.character(df$estimator))]
  
  p <- ggplot(
    df,
    aes(
      x = Average_Treatment_Effect,
      y = .data[[yvar]],
      color = estimator,
      linetype = estimator,
      shape = estimator,
      group = estimator
    )
  ) +
    geom_line(linewidth = 0.7) +
    geom_point(size = 2.0) +
    scale_color_manual(
      values = color_mapping,
      breaks = present_levels,
      limits = present_levels,
      name = "Estimator"
    ) +
    scale_linetype_manual(
      values = linetype_mapping,
      breaks = present_levels,
      limits = present_levels,
      name = "Estimator"
    ) +
    scale_shape_manual(
      values = shape_mapping,
      breaks = present_levels,
      limits = present_levels,
      name = "Estimator"
    ) +
    labs(
      x = x_title,
      y = ylab,
      title = subtitle_text
    ) +
    theme_fig6() +
    guides(
      color = guide_legend(
        order = 1,
        nrow = 2,
        byrow = TRUE,
        override.aes = list(
          linetype = unname(linetype_mapping[present_levels]),
          shape = unname(shape_mapping[present_levels]),
          linewidth = 0.9,
          size = 2.4
        )
      ),
      linetype = "none",
      shape = "none"
    )
  
  if (y_break) {
    p <- p + scale_y_break(break_range, scales = break_scale)
  }
  
  if (!show_legend) {
    p <- p + theme(legend.position = "none")
  }
  
  p
}
# ---------------------------------------------------------
# Panel A: ADTE
# ---------------------------------------------------------
adte_mae <- plot_metric(
  adte_table, "MAE", "Mean Absolute Error", "(A) Mean Absolute Error",
  x_title = NULL,
  show_legend = TRUE
)

adte_rmse <- plot_metric(
  adte_table, "rmse", "RMSE", "(B) RMSE",
  x_title = NULL
)

adte_power <- plot_metric(
  adte_table, "power_percentage", "Statistical Power (%)", "(C) Power",
  x_title = "Average Direct Treatment Effect"
)

adte_coverage <- plot_metric(
  adte_table, "coverage_percentage", "Coverage (%)", "(D) Coverage",
  x_title = "Average Direct Treatment Effect"
)

# ---------------------------------------------------------
# Panel B: AITE
# ---------------------------------------------------------
aite_mae <- plot_metric(
  aite_table, "MAE", "Mean Absolute Error", "(A) Mean Absolute Error",
  x_title = NULL,
  y_break = TRUE, break_range = c(0.2, 1.0), break_scale = 0.5
)

aite_rmse <- plot_metric(
  aite_table, "rmse", "RMSE", "(B) RMSE",
  x_title = NULL,
  y_break = TRUE, break_range = c(0.2, 1.0), break_scale = 0.5
)

aite_power <- plot_metric(
  aite_table, "power_percentage", "Statistical Power (%)", "(C) Power",
  x_title = "Average Indirect Treatment Effect"
)

aite_coverage <- plot_metric(
  aite_table, "coverage_percentage", "Coverage (%)", "(D) Coverage",
  x_title = "Average Indirect Treatment Effect"
)

# ---------------------------------------------------------
# Extract shared legend
# ---------------------------------------------------------
get_legend_only <- function(myplot) {
  tmp <- ggplotGrob(myplot + theme(legend.position = "bottom"))$grobs
  tmp[[which(sapply(tmp, function(x) x$name) == "guide-box")]]
}

shared_legend <- get_legend_only(adte_mae)

# ---------------------------------------------------------
# Build panel grids
# ---------------------------------------------------------
panel_a_grid <- plot_grid(
  adte_mae + theme(legend.position = "none"),
  adte_rmse + theme(legend.position = "none"),
  adte_power + theme(legend.position = "none"),
  adte_coverage + theme(legend.position = "none"),
  ncol = 2,
  align = "hv"
)

panel_b_grid <- plot_grid(
  aite_mae + theme(legend.position = "none"),
  aite_rmse + theme(legend.position = "none"),
  aite_power + theme(legend.position = "none"),
  aite_coverage + theme(legend.position = "none"),
  ncol = 2,
  align = "hv"
)

panel_a_header <- ggdraw() +
  draw_label("Panel A. Average Direct Treatment Effect", x = 0.5, y = 0.5, size = 12)

panel_b_header <- ggdraw() +
  draw_label("Panel B. Average Indirect Treatment Effect", x = 0.5, y = 0.5, size = 12)

panel_a <- plot_grid(
  panel_a_header,
  panel_a_grid,
  ncol = 1,
  rel_heights = c(0.1, 1)
)

panel_b <- plot_grid(
  panel_b_header,
  panel_b_grid,
  ncol = 1,
  rel_heights = c(0.1, 1)
)

# ---------------------------------------------------------
# Final figure
# ---------------------------------------------------------
spacer <- ggdraw()
figure6 <- plot_grid(
  panel_a,
  spacer,
  panel_b,
  shared_legend,
  ncol = 1,
  rel_heights = c(1,0.1, 1, 0.16)
)

print(figure6)

# ---------------------------------------------------------
# Save
# ---------------------------------------------------------
ggsave(
  filename = file.path("simulate_base", "Figure6_ADTE_AITE.pdf"),
  plot = figure6,
  width = 7,
  height = 8,
  units = "in",
  dpi = 600
)

ggsave(
  filename = file.path("simulate_base", "Figure6_ADTE_AITE.pdf"),
  plot = figure6,
  width = 7,
  height = 8.5,
  units = "in",
  dpi = 600
)

