  ">100",   11.588, "Excluding: Hájek",              17.935, 22.429,
  ">100",   11.588, "Representative: Diff-in-Means", 13.245, 16.145
)

cadte_table$degree_group <- factor(
  cadte_table$degree_group,
  levels = c("1–20", "21–50", "51–70", "71–100", ">100")
)

estimator_levels <- c(
  "Representative: Diff-in-Means",
  "Excluding: Diff-in-Means",
  "Excluding: Horvitz-Thompson",
  "Excluding: Hájek"
)

cadte_table$estimator <- factor(cadte_table$estimator, levels = estimator_levels)

# ------------------------------------------------------------
# Same aesthetics as Figure 6
# ------------------------------------------------------------
color_mapping <- c(
  "Representative: Diff-in-Means" = "#1F4E79",   # deep navy
  "Excluding: Diff-in-Means" = "#8B1E3F",        # dark red
  "Excluding: Horvitz-Thompson" = "#2F6B3B",     # dark green
  "Excluding: Hájek" = "#7A6F64"                 # muted brown-gray
)

linetype_mapping <- c(
  "Representative: Diff-in-Means" = "solid",
  "Excluding: Diff-in-Means" = "44",
  "Excluding: Horvitz-Thompson" = "dotted",
  "Excluding: Hájek" = "dotdash"
)

shape_mapping <- c(
  "Representative: Diff-in-Means" = 16,
  "Excluding: Diff-in-Means" = 17,
  "Excluding: Horvitz-Thompson" = 15,
  "Excluding: Hájek" = 18
)

# ------------------------------------------------------------
# Theme
# ------------------------------------------------------------
theme_fig7 <- function() {
  theme_minimal(base_size = 10) +
    theme(
      panel.grid.major.x = element_blank(),
      panel.grid.minor = element_blank(),
      panel.grid.major.y = element_line(color = "grey92", linewidth = 0.25),
      panel.background = element_rect(fill = "white", color = NA),
      plot.background = element_rect(fill = "white", color = NA),
      plot.title = element_text(size = 11, hjust = 0.5, face = "plain"),
      axis.title = element_text(size = 10),
      axis.text = element_text(size = 9),
      legend.position = "bottom",
      legend.box = "horizontal",
      legend.key.width  = unit(3, "lines"),
      legend.key.height = unit(1.0, "lines"),
      legend.spacing.x  = unit(2, "cm"),
      legend.text = element_text(size = 8.5, margin = margin(r = 4)),
      legend.title = element_text(size = 9),
      plot.margin = margin(4, 4, 4, 4)
    )
}

# ------------------------------------------------------------
# Helper for shared legend
# ------------------------------------------------------------
get_legend <- function(myplot) {
  tmp <- ggplotGrob(myplot + theme(legend.position = "bottom"))$grobs
  tmp[[which(sapply(tmp, function(x) x$name) == "guide-box")]]
}

# ------------------------------------------------------------
# Generic plotting function
# ------------------------------------------------------------
plot_cadte_metric <- function(yvar, ylab, panel_title, show_legend = FALSE) {
  p <- ggplot(
    cadte_table,
    aes(
      x = degree_group,
      y = .data[[yvar]],
      color = estimator,
      linetype = estimator,
      shape = estimator,
      group = estimator
    )
  ) +
    geom_line(linewidth = 0.7) +
    geom_point(size = 2.0) +
    scale_color_manual(
      values = color_mapping,
      breaks = estimator_levels,
      name = "Estimator"
    ) +
    scale_linetype_manual(
      values = linetype_mapping,
      breaks = estimator_levels,
      name = "Estimator"
    ) +
    scale_shape_manual(
      values = shape_mapping,
      breaks = estimator_levels,
      name = "Estimator"
    ) +
    labs(
      x = "Degree Group",
      y = ylab,
      title = panel_title
    ) +
    theme_fig7() +
    guides(
      color = guide_legend(
        order = 1,
        nrow = 2,
        byrow = TRUE,
        override.aes = list(
          linetype = unname(linetype_mapping[estimator_levels]),
          shape = unname(shape_mapping[estimator_levels]),
          linewidth = 0.9,
          size = 2.4
        )
      ),
      linetype = "none",
      shape = "none"
    )
  
  if (!show_legend) {
    p <- p + theme(legend.position = "none")
  }
  
  p
}

# ------------------------------------------------------------
# Panel plots
# ------------------------------------------------------------
cadte_mae <- plot_cadte_metric(
  yvar = "MAE",
  ylab = "Mean Absolute Error",
  panel_title = "(A) Mean Absolute Error",
  show_legend = TRUE
)

cadte_rmse <- plot_cadte_metric(
  yvar = "RMSE",
  ylab = "Root Mean Squared Error",
  panel_title = "(B) Root Mean Squared Error",
  show_legend = FALSE
)

# ------------------------------------------------------------
# Shared legend
# ------------------------------------------------------------
shared_legend <- get_legend(cadte_mae)

# ------------------------------------------------------------
# Final Figure 7
# ------------------------------------------------------------

combined_plot <- plot_grid(
  cadte_mae + theme(legend.position = "none"),
  cadte_rmse + theme(legend.position = "none"),
  nrow = 1,
  align = "h"
)

figure7 <- plot_grid(
  combined_plot,
  shared_legend,
  ncol = 1,
  rel_heights = c(1, 0.2)
)



print(figure7)

